-- query the database to get results

-- ******************
-- 1) lexical queries
-- ******************
SELECT 	supplier_id, content
FROM 	supplier
WHERE 	content_tsv @@ websearch_to_tsquery( 'english', 'delivery issues contract breach' )
LIMIT 5;

-- evaluating the output of the above query
select 	supplier_id, on_time_delivery_pct, contract_breach_count
from 	supplier_data
where	supplier_id in ('SUP1000', 'SUP1001', 'SUP1002', 'SUP1003', 'SUP1004')
order by supplier_id;

-- combine the SQL + Lexical (Hybird approach)
-- lexical with SQL (hybrid) search
select	sd.supplier_id, sd.on_time_delivery_pct, sd.contract_breach_count
from	supplier_data sd, supplier s
where	sd.supplier_id = s.supplier_id
-- and 	s.content_tsv @@ websearch_to_tsquery('english', 'delivery issues contract breach')
and		sd.on_time_delivery_pct < 75
and		sd.contract_breach_count > 2
order by sd.on_time_delivery_pct, sd.contract_breach_count
limit 3;

select	sd.supplier_id, sd.on_time_delivery_pct, sd.contract_breach_count
from	supplier_data sd, supplier s
where	sd.supplier_id = s.supplier_id
and 	s.content_tsv @@ websearch_to_tsquery('english', 'delivery issues contract breach')
and		sd.on_time_delivery_pct < 75
and		sd.contract_breach_count > 2
order by sd.on_time_delivery_pct, sd.contract_breach_count
limit 3;
-- "SUP1343", "SUP1782", "SUP1221"

select 
    sd.supplier_id, 
    sd.on_time_delivery_pct, 
    sd.contract_breach_count,
    ts_rank(s.content_tsv, websearch_to_tsquery('english', 'delivery issues contract breach')) as rank
from supplier_data sd
join supplier s on sd.supplier_id = s.supplier_id
where 
    s.content_tsv @@ websearch_to_tsquery('english', 'delivery issues contract breach')
    and sd.on_time_delivery_pct < 75
    and sd.contract_breach_count > 2
order by rank desc, sd.on_time_delivery_pct, sd.contract_breach_count
limit 3;
-- "SUP1343", "SUP1782", "SUP1221"


-- Relax query (OR) : giving the | symbol
SELECT supplier_id,content FROM supplier
WHERE content_tsv @@ websearch_to_tsquery('english', 'fast lead time | low risk')
limit 3;
-- "SUP1033", "SUP1035", "SUP1044"

-- RANK
SELECT supplier_id, content,
    ts_rank(content_tsv, websearch_to_tsquery('english', 'fast lead time | low risk')) AS rank -- Ranks the results based on proximity
FROM supplier
WHERE content_tsv @@ websearch_to_tsquery('english', 'fast lead time | low risk') -- Filter condition
ORDER BY rank DESC
LIMIT 3;
-- "SUP1647", "SUP1650", "SUP1835"


